module top_module(underflow, b, eq, leds);input underflow, b, eq;
output [2:0] leds;

reg [2:0] leds;

always @(underflow, b, eq)
begin
    if(underflow)
        leds[0] = 1;
    else
        leds[0] = 0;

    if(b)
        leds[1] = 1;
    else
        leds[1] = 0;

    if(eq)
        leds[2] = 1;
    else
        leds[2] = 0;
end
endmodule
